const reviews = $input.first().json.reviews || [];
const unanswered = reviews.filter(r => !r.reviewReply || !r.reviewReply.comment);
const toProcess = unanswered.slice(0, 5);
return [{ json: { count: toProcess.length, reviews: toProcess } }];

const data = $input.first().json;
const reviews = data.reviews;

let reviewsText = '';
reviews.forEach((r, i) => {
  const rating = r.starRating || 'N/A';
  const author = r.reviewer?.displayName || 'Cliente anonimo';
  const comment = r.comment || '(nessun commento scritto)';
  const date = r.createTime ? new Date(r.createTime).toLocaleDateString('it-IT') : 'data sconosciuta';
  reviewsText += `--- Recensione ${i+1} ---
Autore: ${author}
Voto: ${rating} stelle
Data: ${date}
Testo: ${comment}

`;
});

const prompt = `Sei l'assistente di una PMI italiana. Genera risposte professionali, calde e autentiche per le seguenti recensioni Google.

REGOLE:
- Voto 4-5 stelle: ringraziamento personalizzato, cita dettagli specifici del commento se presenti, invita a tornare.
- Voto 1-3 stelle: tono empatico, scuse sincere, offerta di risoluzione offline (invita a contattarvi direttamente), mai essere difensivo.
- Lunghezza: 2-4 frasi. Tono: professionale ma umano. Lingua: italiano.

FORMATO RISPOSTA: JSON array come segue, senza testo aggiuntivo:
[{\

}, ...]

Recensioni:
${reviewsText}`;

return [{ json: { prompt, count: reviews.length, reviews } }];

const claudeRaw = $input.first().json.content[0].text;
const reviews = $('Prepara Prompt Claude').first().json.reviews;

let risposte = [];
try {
  const cleaned = claudeRaw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  risposte = JSON.parse(cleaned);
} catch(e) {
  risposte = [{ indice: 1, risposta: claudeRaw }];
}

const result = risposte.map((r, i) => {
  const review = reviews[i] || {};
  return {
    indice: r.indice || i + 1,
    autore: review.reviewer?.displayName || 'Cliente anonimo',
    voto: review.starRating || 'N/A',
    commento: review.comment || '(nessun commento)',
    bozza_risposta: r.risposta || ''
  };
});

return [{ json: { risposte: result, count: result.length } }];

const data = $input.first().json;
const risposte = data.risposte;
const today = new Date().toLocaleDateString('it-IT', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });

let cardsHtml = '';
risposte.forEach(r => {
  const votoNum = parseInt(r.voto) || 0;
  const stars = '⭐'.repeat(votoNum);
  const isNegative = votoNum <= 3;
  const headerColor = isNegative ? '#c0392b' : '#27ae60';
  const label = isNegative ? '🔴 Recensione Negativa' : '🟢 Recensione Positiva';

  cardsHtml += `
  <div style="border:1px solid #ddd;border-radius:8px;margin:24px 0;overflow:hidden;">
    <div style="background:${headerColor};color:white;padding:12px 20px;font-weight:bold;font-size:15px;">
      ${label} &mdash; ${stars} (${r.voto}/5) &mdash; ${r.autore}
    </div>
    <div style="padding:20px;">
      <p style="margin:0 0 8px;"><strong>💬 Commento del cliente:</strong></p>
      <blockquote style="background:#f8f8f8;border-left:4px solid #ccc;padding:10px 16px;margin:0 0 16px;font-style:italic;color:#555;">${r.commento}</blockquote>
      <p style="margin:0 0 8px;"><strong>✍️ Bozza risposta generata da Claude:</strong></p>
      <div style="background:#eaf6fb;border-left:4px solid #2980b9;padding:12px 16px;margin:0 0 12px;color:#1a1a1a;">${r.bozza_risposta}</div>
      <p style="font-size:12px;color:#999;margin:0;">👆 Copia il testo sopra e incollalo su <a href="https://business.google.com" style="color:#2980b9;">Google Business Profile</a> per pubblicare la risposta.</p>
    </div>
  </div>`;
});

const html = `<!DOCTYPE html><html><body style="font-family:Arial,sans-serif;max-width:680px;margin:0 auto;padding:24px;color:#222;">
  <h2 style="color:#2c3e50;margin-bottom:4px;">📋 Recensioni Google da rispondere</h2>
  <p style="color:#666;margin-top:4px;">Riepilogo del ${today}</p>
  <p>Hai <strong>${risposte.length} nuova/e recensione/i</strong> senza risposta. Di seguito le bozze generate da Claude &mdash; copia e incolla su Google Business Profile.</p>
  ${cardsHtml}
  <hr style="margin:30px 0;border:none;border-top:1px solid #eee;">
  <p style="font-size:11px;color:#bbb;">Generato automaticamente da n8n Automation Pack Italia &mdash; Workflow 05</p>
</body></html>`;

return [{ json: { html, subject: `📋 ${risposte.length} nuova/e recensione/i Google da rispondere — ${today}` } }];
